{
  "domain_analysis": {
    "business_context": "A logistics platform introducing automated route optimization for drivers at shift start, with dynamic recalculation triggers, customer notification windows, vehicle-class constraints, and configurable stop duration. This spans multiple bounded contexts: route planning, fleet/driver management, delivery lifecycle, and customer notifications.",
    "bounded_context": "Multiple bounded contexts identified: (1) Route Planning — owns route calculation, optimization algorithms, recalculation triggers, and stop-time estimates; (2) Fleet Management — owns driver profiles, shift lifecycle, vehicle classes, zone assignments, and licensing constraints; (3) Delivery Management — owns delivery lifecycle (pending, in-transit, failed, completed), zone assignment of parcels, and parcel attributes (size, weight, vehicle class requirement); (4) Customer Notification — owns notification triggers, delivery proximity windows, and communication channels. The feature request conflates all four, which is a domain risk.",
    "ubiquitous_language": [
      { "term": "Shift", "definition": "A bounded work period during which a driver is active and eligible for delivery assignments. A shift has a start time, end time, and is associated with exactly one zone and one vehicle." },
      { "term": "Zone", "definition": "A geographic region used to partition deliveries and assign drivers. A driver operates in exactly one zone per shift." },
      { "term": "Optimized Route", "definition": "An ordered sequence of delivery stops calculated to minimize total travel time or distance for a driver within their zone, subject to vehicle-class and time constraints." },
      { "term": "Pending Delivery", "definition": "A delivery that has been created and assigned to a zone but not yet assigned to a driver's route or completed." },
      { "term": "Vehicle Class", "definition": "A classification of vehicle capability (e.g., motorcycle, van, truck, freight). Determines which deliveries a driver is eligible to carry based on parcel requirements." },
      { "term": "Licensed Vehicle Class", "definition": "The vehicle class(es) a driver is certified and authorized to operate. Acts as a hard constraint on delivery assignment eligibility." },
      { "term": "Route Recalculation", "definition": "The process of re-optimizing the remaining stops on a driver's active route in response to a defined trigger event." },
      { "term": "Recalculation Trigger", "definition": "A domain event that mandates route re-optimization: new delivery added to zone, delivery marked as failed, or driver deviation from suggested route." },
      { "term": "Next-3-Stops Window", "definition": "The set of the next three upcoming delivery stops on a driver's active route. Entry into this window triggers customer notification." },
      { "term": "Stop Duration", "definition": "The estimated time a driver spends at each delivery stop. Defaults to 4 minutes but is overridable per zone by the operations team." },
      { "term": "Driver Deviation", "definition": "When a driver's actual GPS position or stop sequence diverges from the suggested optimized route beyond a defined threshold." },
      { "term": "Failed Delivery", "definition": "A delivery attempt that was unsuccessful (e.g., customer unavailable, address inaccessible). Removed from the active route and triggers recalculation." },
      { "term": "Delivery-Vehicle Compatibility", "definition": "The rule that a delivery's required vehicle class must be equal to or lower than the driver's licensed vehicle class. This is an invariant, not a preference." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "When a driver starts their shift, the system must automatically generate an optimized route from all pending deliveries in the driver's assigned zone that are compatible with their vehicle class.",
      "invariant": false,
      "invariant_justification": "The automatic assignment at shift start is a business workflow policy. The system could theoretically allow manual assignment or delayed optimization. However, the vehicle-class filter within it IS invariant (see BR-5).",
      "testable_assertion": "Given a driver starting a shift in Zone A with 10 pending deliveries (8 compatible, 2 incompatible with vehicle class), the system generates a route containing exactly the 8 compatible deliveries in an optimized order."
    },
    {
      "id": "BR-2",
      "rule": "The route must be recalculated when a new pending delivery is added to the driver's active zone.",
      "invariant": false,
      "invariant_justification": "This is an operational policy about when to re-optimize. A business decision could change this to batch recalculations or add a cooldown period. The system is not corrupt if recalculation is delayed.",
      "testable_assertion": "Given a driver with an active route in Zone A, when a new compatible delivery is added to Zone A, then the route is recalculated to include the new delivery within the defined SLA."
    },
    {
      "id": "BR-3",
      "rule": "The route must be recalculated when a delivery on the active route is marked as failed.",
      "invariant": false,
      "invariant_justification": "Operational policy. The failed delivery must be removed (that is invariant — you cannot deliver something that failed), but the recalculation timing is policy.",
      "testable_assertion": "Given a driver with 5 remaining stops, when stop #3 is marked as failed, then the route is recalculated with the remaining 4 stops in optimized order, and the failed delivery is no longer on the route."
    },
    {
      "id": "BR-4",
      "rule": "The route must be recalculated when the driver manually deviates from the suggested route.",
      "invariant": false,
      "invariant_justification": "Operational policy. Deviation detection threshold and recalculation response are configurable business decisions.",
      "testable_assertion": "Given a driver whose GPS position or stop sequence deviates from the suggested route beyond the defined threshold, the system triggers a route recalculation from the driver's current position."
    },
    {
      "id": "BR-5",
      "rule": "A driver must never be assigned a delivery that requires a vehicle class exceeding their licensed vehicle class. A motorcycle driver cannot carry freight shipments.",
      "invariant": true,
      "invariant_justification": "This is a physical and legal constraint. A motorcycle physically cannot carry freight. Violating this creates safety hazards, regulatory violations, and guaranteed delivery failure. If this rule is broken, the system state is corrupt.",
      "testable_assertion": "Given a motorcycle-licensed driver, the system must never include a freight-class delivery on their route. Any attempt to assign such a delivery must be rejected with an error, regardless of zone, urgency, or manual override."
    },
    {
      "id": "BR-6",
      "rule": "Customers must be notified when their delivery enters the 'next 3 stops' window on the driver's active route.",
      "invariant": false,
      "invariant_justification": "Notification is a business policy. The window size (3 stops) is a configurable parameter. Missing a notification degrades customer experience but does not corrupt system state.",
      "testable_assertion": "Given a driver completing stop N, when stop N+3's delivery was not previously in the next-3-stops window and now is, the customer for that delivery receives a notification."
    },
    {
      "id": "BR-7",
      "rule": "The default estimated time per delivery stop is 4 minutes. This value can be overridden per zone by the operations team.",
      "invariant": false,
      "invariant_justification": "This is a configurable operational parameter. The 4-minute default and the per-zone override are business policies that can change without corrupting system state.",
      "testable_assertion": "Given Zone A has no override, stop duration defaults to 4 minutes. Given Zone B has an override of 6 minutes, stop duration for Zone B is 6 minutes. ETA calculations use the applicable stop duration."
    },
    {
      "id": "BR-8",
      "rule": "A failed delivery must be removed from the driver's active route immediately upon being marked as failed.",
      "invariant": true,
      "invariant_justification": "A failed delivery cannot be delivered. If it remains on the route, the driver is directed to a stop that cannot be completed, wasting time and corrupting route integrity. This is a state consistency constraint.",
      "testable_assertion": "Given a delivery is marked as failed, it must not appear in any driver's active route within the same transaction or event processing cycle."
    },
    {
      "id": "BR-9",
      "rule": "A driver can only be assigned deliveries within their currently assigned zone for the active shift.",
      "invariant": true,
      "invariant_justification": "Zone boundaries define operational accountability, insurance coverage areas, and dispatching logic. Cross-zone assignment without explicit zone reassignment corrupts the dispatching model and breaks zone-based SLA tracking.",
      "testable_assertion": "Given a driver assigned to Zone A, the system must reject any delivery in Zone B from being added to their route unless the driver's zone assignment is formally changed."
    },
    {
      "id": "BR-10",
      "rule": "Route recalculation must preserve already-completed stops and only re-optimize the remaining stops.",
      "invariant": true,
      "invariant_justification": "Completed deliveries are historical facts. Recalculating a route that alters completed stops corrupts delivery records and timelines. The route is append-only for completed segments.",
      "testable_assertion": "Given a driver has completed stops 1-3 of a 7-stop route, when recalculation is triggered, stops 1-3 remain unchanged and only stops 4-7 (plus any new additions) are re-optimized."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A driver starts their shift in Zone A with a van-class vehicle, and there are 12 pending deliveries in Zone A (10 van-compatible, 2 freight-only)",
      "when": "The shift is activated",
      "then": "An optimized route is generated containing exactly the 10 van-compatible deliveries in an optimized sequence, and the 2 freight-only deliveries remain unassigned"
    },
    {
      "id": "AC-2",
      "given": "A driver has an active route with 6 remaining stops in Zone A",
      "when": "A new van-compatible delivery is added to Zone A",
      "then": "The route is recalculated to include the new delivery, preserving completed stops, and the driver sees the updated route"
    },
    {
      "id": "AC-3",
      "given": "A driver has an active route and delivery at stop #4 is marked as failed",
      "when": "The failure is recorded",
      "then": "Stop #4 is removed from the route, the route is recalculated with remaining stops, and the failed delivery transitions to the appropriate failed state in the delivery lifecycle"
    },
    {
      "id": "AC-4",
      "given": "A driver deviates from the suggested route beyond the configured threshold",
      "when": "The deviation is detected",
      "then": "The route is recalculated from the driver's current position with remaining undelivered stops"
    },
    {
      "id": "AC-5",
      "given": "A driver completes a stop and delivery X is now within the next 3 upcoming stops",
      "when": "The route position advances",
      "then": "Customer for delivery X receives a notification with estimated arrival time based on the applicable zone stop duration"
    },
    {
      "id": "AC-6",
      "given": "Operations team has set Zone B stop duration to 6 minutes (overriding the 4-minute default)",
      "when": "An ETA is calculated for a delivery in Zone B",
      "then": "The ETA uses 6 minutes per stop plus travel time, not the 4-minute default"
    },
    {
      "id": "AC-7",
      "given": "A route recalculation is triggered (any trigger) and the new optimized order changes which deliveries are in the next-3-stops window",
      "when": "The recalculated route is applied",
      "then": "Customers newly entering the next-3-stops window are notified, and customers who were previously notified but are no longer in the window are NOT sent a cancellation (notification is fire-once)"
    },
    {
      "id": "AC-8",
      "given": "A motorcycle-class driver is active in Zone A and a new freight delivery is added to Zone A",
      "when": "Route recalculation is triggered",
      "then": "The freight delivery is NOT added to the motorcycle driver's route, even though it is in the same zone"
    },
    {
      "id": "AC-9",
      "given": "Multiple drivers are active in the same zone",
      "when": "A new delivery is added to the zone",
      "then": "The delivery is assigned to exactly one eligible driver's route (no double-assignment) and that driver's route is recalculated"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Driver starts shift but there are zero pending compatible deliveries in their zone",
      "expected_behavior": "Driver is assigned an empty route and enters an idle state. When a compatible delivery arrives in their zone, recalculation triggers and generates a route with that single delivery."
    },
    {
      "scenario": "All remaining deliveries on a route are marked as failed",
      "expected_behavior": "Driver's route becomes empty. Driver enters idle state awaiting new deliveries. No customer notifications are sent for an empty route."
    },
    {
      "scenario": "Route recalculation is triggered while a previous recalculation is still in progress",
      "expected_behavior": "The system must handle concurrent recalculation requests safely. Either queue them (latest wins) or debounce with a short window. A route must never be in an inconsistent state from interleaved recalculations."
    },
    {
      "scenario": "A new delivery is added to a zone with multiple active drivers — all eligible",
      "expected_behavior": "The delivery must be assigned to exactly one driver. Assignment strategy (nearest, least-loaded, best-fit) is a policy decision, but the invariant is: no double-assignment, no orphaned delivery."
    },
    {
      "scenario": "Customer notification is triggered, but then route recalculation moves that delivery outside the next-3 window",
      "expected_behavior": "The notification already sent is not retracted. The customer should not receive a confusing 'you are no longer next' message. If the delivery re-enters the window later, a duplicate notification policy must be defined (recommend: do not re-notify)."
    },
    {
      "scenario": "Driver deviates from route but deviation is toward the next stop (e.g., taking a shortcut)",
      "expected_behavior": "Deviation detection must account for progress toward the next stop. A beneficial deviation that still reaches the next planned stop should ideally not trigger a full recalculation. The threshold definition must consider direction, not just distance from the planned path."
    },
    {
      "scenario": "Operations team changes zone stop duration while drivers have active routes with existing ETAs",
      "expected_behavior": "Active routes should recalculate ETAs with the new stop duration. Customers already notified retain their original ETA; newly notified customers get the updated ETA. The change should not trigger a full route recalculation (stop order unchanged), only an ETA refresh."
    },
    {
      "scenario": "A delivery is reassigned from one zone to another while a driver in the original zone has it on their active route",
      "expected_behavior": "The delivery must be removed from the original driver's route (triggering recalculation) and become available for assignment in the new zone. This is equivalent to a failure/cancellation from the route's perspective."
    },
    {
      "scenario": "Driver's shift ends while deliveries remain on their route",
      "expected_behavior": "Undelivered stops must be released back to pending status in the zone for reassignment to another driver or the next shift. Customer notifications for unreached stops should be handled (e.g., 'delivery rescheduled' notification)."
    }
  ],

  "business_impact": {
    "financial": "Route optimization directly reduces fuel costs, overtime pay, and increases deliveries-per-shift. Dynamic recalculation captures revenue from new deliveries added mid-shift instead of deferring them. Incorrect vehicle-class assignment could result in regulatory fines and failed delivery costs. The 4-minute stop duration default directly impacts capacity planning — if too low, routes are over-packed and SLAs are missed; if too high, driver utilization drops.",
    "operational": "Significant operational complexity: the system must handle real-time GPS tracking, concurrent route recalculations for many drivers, and cross-context event propagation (delivery lifecycle events → route planning → customer notifications). The recalculation triggers create a potential thundering-herd problem if many deliveries fail or arrive simultaneously. Operations team needs a dashboard to manage per-zone stop duration overrides and monitor route health.",
    "user": "Customers gain transparency via the next-3-stops notification, improving satisfaction and reducing 'where is my delivery' support calls. Drivers benefit from optimized routes (less decision fatigue, fewer miles) but may resist if the system overrides their local knowledge. Frequent recalculations mid-drive could be distracting or frustrating for drivers — UX for presenting route changes is critical.",
    "risk": "High risk of notification spam if recalculation frequency is unthrottled — customers could receive multiple 'you are next' notifications. Race conditions in multi-driver zones for delivery assignment could cause double-assignment or delivery orphaning. Vehicle-class enforcement failure is a safety and legal liability. Deviation detection sensitivity is a tuning challenge — too sensitive causes unnecessary recalculations, too lax misses real deviations.",
    "stakeholders_affected": [
      { "group": "Drivers", "impact": "Core workflow change — routes are now system-assigned rather than manually planned. Must trust optimization quality. Frequent mid-route changes could be disruptive. Vehicle-class constraints may limit earning potential for some drivers." },
      { "group": "Customers", "impact": "Positive — proactive delivery notifications improve experience. Risk of notification fatigue if recalculations cause repeated alerts. ETA accuracy depends on stop-duration calibration." },
      { "group": "Operations Team", "impact": "New administrative responsibility for zone stop-duration overrides. Need monitoring tools for route health, recalculation frequency, and delivery assignment fairness across drivers." },
      { "group": "Dispatchers", "impact": "Role potentially reduced or changed — automatic assignment replaces manual dispatching. Need to define what manual overrides dispatchers retain." },
      { "group": "Finance/Compliance", "impact": "Vehicle-class enforcement has regulatory implications. Route optimization data feeds into cost analysis and driver compensation models." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec is a high-level product narrative that leaves several critical operational details undefined. Deviation threshold is unspecified. Multi-driver assignment strategy is absent. Notification idempotency is not addressed. The interplay between recalculation triggers and notification state introduces complexity that the spec does not acknowledge. Vehicle-class hierarchy is mentioned by example but not formally defined. The bounded context boundaries are implied but not explicit, creating risk of a monolithic implementation that conflates route planning, fleet management, and notifications.",
    "high_confidence_areas": [
      "Vehicle-class constraint is a hard invariant — physically and legally non-negotiable",
      "Route recalculation triggers are clearly enumerated (3 triggers)",
      "Stop duration default (4 min) and override mechanism are clear",
      "Customer notification trigger (next-3-stops) is well-defined"
    ],
    "low_confidence_areas": [
      "Deviation detection: no threshold, no definition of what constitutes deviation, no mention of GPS accuracy tolerance",
      "Multi-driver assignment: spec says 'driver' singular but zones will have multiple drivers — assignment algorithm is undefined",
      "Notification idempotency: no guidance on what happens when recalculation shuffles the next-3 window repeatedly",
      "Vehicle class hierarchy: only motorcycle vs freight example given — full class taxonomy is undefined",
      "Recalculation throttling: no mention of debouncing or rate-limiting — could overwhelm the system under load",
      "Shift end behavior: no spec for what happens to undelivered route stops when a shift ends"
    ],
    "assumptions": [
      "A driver is assigned to exactly one zone per shift",
      "Vehicle class compatibility is a strict hierarchy (motorcycle < van < truck < freight), not a tag-based system",
      "The 'next 3 stops' notification is fire-once per customer per delivery — entering and leaving the window does not retrigger",
      "Route optimization considers travel time between stops, not just stop count",
      "A delivery can only be on one driver's active route at a time (no double-assignment)",
      "Dispatchers exist as a stakeholder even though the spec does not mention them — automatic assignment impacts their role"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "Driver deviation threshold is completely unspecified. What constitutes a 'deviation'? Is it distance from planned path? Skipping a stop? Taking an alternate road? Without a clear definition, the recalculation trigger cannot be implemented correctly, and an overly sensitive threshold will cause constant recalculations while an overly lenient one defeats the purpose.",
      "affected_stakeholders": ["Drivers", "Operations Team", "Customers"],
      "options": [
        "Define deviation as distance > X meters from planned route segment for > Y seconds",
        "Define deviation as skipping the next planned stop (sequence-based, not GPS-based)",
        "Allow operations team to configure deviation sensitivity per zone"
      ],
      "recommendation": "Use a hybrid: sequence-based deviation (driver does not arrive at next expected stop within ETA + buffer) as primary trigger, with GPS path deviation as secondary. Make thresholds configurable per zone."
    },
    {
      "type": "ambiguity",
      "description": "Multi-driver delivery assignment strategy is undefined. When a new delivery arrives in a zone with 3 active drivers, which driver gets it? The spec implies single-driver zones but real operations have multiple drivers per zone.",
      "affected_stakeholders": ["Drivers", "Dispatchers", "Customers"],
      "options": [
        "Assign to driver with fewest remaining stops (load balancing)",
        "Assign to driver geographically nearest to the new delivery",
        "Assign to driver whose route would have the least total-distance increase (optimal insertion)",
        "Let dispatchers manually assign, with system suggesting the optimal driver"
      ],
      "recommendation": "Optimal insertion (least total-distance increase) as default, with dispatcher override capability. This maximizes efficiency while preserving human judgment for edge cases."
    },
    {
      "type": "ambiguity",
      "description": "Customer notification behavior during rapid recalculations is undefined. If 3 recalculations happen in 5 minutes, a customer could enter and leave the next-3 window multiple times. The spec does not address idempotency, retraction, or throttling of notifications.",
      "affected_stakeholders": ["Customers", "Operations Team"],
      "options": [
        "Fire-once: customer is notified the first time they enter the window, never again for that delivery",
        "Latest-state: always reflect the current route state, including 'no longer next' messages",
        "Debounced: wait N minutes after a recalculation before sending notifications to avoid churn"
      ],
      "recommendation": "Fire-once with debounce. Notify the customer the first time they enter the next-3 window, do not retract. Apply a 2-minute debounce after recalculation before evaluating notification eligibility."
    },
    {
      "type": "missing_context",
      "description": "Vehicle class taxonomy is not defined. The spec gives one example (motorcycle cannot carry freight) but the full hierarchy, compatibility rules, and edge cases (e.g., can a truck driver carry motorcycle-class parcels?) are not specified.",
      "affected_stakeholders": ["Drivers", "Operations Team", "Compliance"],
      "options": [
        "Define a strict linear hierarchy: motorcycle < van < truck < freight (higher class can carry lower)",
        "Define a tag-based system where each delivery and vehicle has capability tags that must match",
        "Request the full vehicle class matrix from the operations team"
      ],
      "recommendation": "Request the full vehicle class compatibility matrix from operations. A hierarchy is likely correct but must be confirmed — some deliveries may have special requirements (refrigerated, hazmat) that cut across a simple size hierarchy."
    }
  ],

  "rejection_reasons": []
}

